class Solution {
public:
    bool isValidSudoku(vector<vector<char>>& board) {
        int n = board.size();
        vector<vector<bool>> rows(n, vector<bool>(n, false));
        vector<vector<bool>> cols(n, vector<bool>(n, false));
        vector<vector<bool>> boxes(n, vector<bool>(n, false));
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (board[i][j] == '.') continue;
                char num = board[i][j];
                if (rows[i][num - '1'] || cols[j][num - '1'] || boxes[(i/3)*3 + j/3][num - '1'])
                    return false;
                rows[i][num - '1'] = true;
                cols[j][num - '1'] = true;
                boxes[(i/3)*3 + j/3][num - '1'] = true;
            }
        }
        return true;
    }
};
